parameters.jsCode:
const tickets = $input.all();
const chatId = $('Telegram Trigger').first().json.message?.chat?.id 
  || $('Telegram Trigger').first().json.callback_query?.message?.chat?.id;

// Build ticket list in message (plain text)
const ticketList = tickets.map((item, i) => 
  `${i + 1}. ${item.json.ticket_id} - ${item.json.keywords || 'No description'}`
).join('\n');

// Buttons with truncated keywords
const buttons = tickets.map((item, i) => {
  const keywords = item.json.keywords || 'Issue';
  const shortKeywords = keywords.length > 25 ? keywords.substring(0, 25) + '...' : keywords;
  return [{
    text: `${i + 1}. ${shortKeywords}`,
    callback_data: `m||${item.json.ticket_id}`
  }];
});

buttons.push([{
  text: "Don't Upload",
  callback_data: "m||ignore"
}]);

return [{
  json: {
    chat_id: chatId,
    text: `Which ticket is this photo for?\n\n${ticketList}`,
    reply_markup: JSON.stringify({ inline_keyboard: buttons }),
    hasTickets: true
  }
}];
